on_write:
let res = #{ action: "Allow" };
if !payload.contains("epoch") || !payload.contains("coordinates") {
    res.action = "Reject";
    res.reason = "Spatial-Temporal payloads must provide both time (epoch) and space (coordinates)";
}
res

on_read:
let res = #{ payload: payload };
res.match_found = true;
res
